export function welcomeRightClickBytes(): ArrayBuffer {
  return decodeBase64Image(WELCOME_RIGHT_CLICK_BASE64);
}

export function welcomeResultBytes(): ArrayBuffer {
  return decodeBase64Image(WELCOME_RESULT_BASE64);
}

function decodeBase64Image(value: string): ArrayBuffer {
  const binary = atob(value.replace(/\s+/g, ""));
  const buffer = new ArrayBuffer(binary.length);
  const bytes = new Uint8Array(buffer);
  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
  return buffer;
}
